#!/usr/bin/env python3
"""
GPU-accelerated /hidden-embed service for qwen2.5-0.5b.

Offloads embedding work from the CPU fat-stations onto an NVIDIA GPU.
Matches the fat-station /hidden-embed contract EXACTLY:

  Request:  POST /hidden-embed
            Content-Type: application/octet-stream
            body = packed little-endian u32 token ids (the whole prompt)
  Response: raw binary = little-endian f32[hidden_dim]  (qwen2.5-0.5b -> 896 dims, 3584 bytes)

Semantics: MEAN-POOLED final decoder-layer residual (get_x_residual) over the
sequence. In HF Qwen2 terms this is hidden_states[-1] (PRE final RMSNorm) mean-pooled
over the seq dim. The post-final-norm variant (last_hidden_state) is selectable via
--variant post for validation/A-B testing.

Launch:
  python3 gpu_hidden_embed.py --port 8093 --host 0.0.0.0 --variant pre
"""
import argparse
import struct
import sys
import time
from http.server import BaseHTTPRequestHandler, ThreadingHTTPServer

import torch
from transformers import AutoModelForCausalLM

MODEL_ID = "Qwen/Qwen2.5-0.5B-Instruct"

# globals populated in main()
MODEL = None
DEVICE = None
VARIANT = "pre"  # "pre" = hidden_states[-1] (pre-final-norm); "post" = last_hidden_state


def embed(token_ids, variant):
    """Return f32 numpy-less list of length hidden_dim (mean-pooled)."""
    with torch.no_grad():
        ids = torch.tensor([token_ids], dtype=torch.long, device=DEVICE)
        out = MODEL.model(ids, output_hidden_states=True, use_cache=False)
        if variant == "post":
            # post-final-RMSNorm residual stream
            hs = out.last_hidden_state  # [1, seq, hidden]
        else:
            # pre-final-norm: output of the last decoder layer
            hs = out.hidden_states[-1]  # [1, seq, hidden]
        vec = hs[0].mean(dim=0)  # mean-pool over sequence -> [hidden]
        return vec.float().cpu().contiguous()


class Handler(BaseHTTPRequestHandler):
    protocol_version = "HTTP/1.1"

    def log_message(self, *a):  # quiet
        pass

    def _send(self, code, body=b"", ctype="application/octet-stream"):
        self.send_response(code)
        self.send_header("Content-Type", ctype)
        self.send_header("Content-Length", str(len(body)))
        self.end_headers()
        if body:
            self.wfile.write(body)

    def do_GET(self):
        if self.path in ("/", "/health"):
            self._send(200, b"ok", "text/plain")
        else:
            self._send(404, b"not found", "text/plain")

    def do_POST(self):
        if self.path != "/hidden-embed":
            self._send(404, b"not found", "text/plain")
            return
        try:
            n = int(self.headers.get("Content-Length", 0))
            raw = self.rfile.read(n)
            if len(raw) % 4 != 0:
                self._send(400, b"body length not multiple of 4", "text/plain")
                return
            ntok = len(raw) // 4
            token_ids = list(struct.unpack("<%dI" % ntok, raw))
            # per-request variant override for validation: ?variant=post
            variant = VARIANT
            if "?" in self.path:
                pass
            q = self.headers.get("X-Variant")
            if q in ("pre", "post"):
                variant = q
            t = time.time()
            vec = embed(token_ids, variant)
            body = struct.pack("<%df" % vec.numel(), *vec.tolist())
            self._send(200, body)
            sys.stderr.write(
                "embed ntok=%d dim=%d variant=%s %.3fs\n"
                % (ntok, vec.numel(), variant, time.time() - t)
            )
        except Exception as e:  # noqa
            import traceback
            traceback.print_exc()
            self._send(500, str(e).encode(), "text/plain")


def main():
    global MODEL, DEVICE, VARIANT
    ap = argparse.ArgumentParser()
    ap.add_argument("--port", type=int, default=8093)
    ap.add_argument("--host", default="0.0.0.0")
    ap.add_argument("--variant", choices=["pre", "post"], default="pre")
    ap.add_argument("--model", default=MODEL_ID)
    args = ap.parse_args()
    VARIANT = args.variant

    if not torch.cuda.is_available():
        sys.stderr.write("FATAL: CUDA not available\n")
        sys.exit(1)
    DEVICE = "cuda"
    sys.stderr.write("loading %s onto %s (fp16)...\n" % (args.model, DEVICE))
    MODEL = AutoModelForCausalLM.from_pretrained(
        args.model, torch_dtype=torch.float16
    ).to(DEVICE).eval()
    sys.stderr.write(
        "loaded. gpu_mem_alloc=%.2fGB hidden=%d default_variant=%s\n"
        % (
            torch.cuda.memory_allocated() / 1e9,
            MODEL.config.hidden_size,
            VARIANT,
        )
    )
    # warmup
    _ = embed([785, 6722, 315], VARIANT)
    sys.stderr.write("warmup done\n")

    srv = ThreadingHTTPServer((args.host, args.port), Handler)
    sys.stderr.write("serving /hidden-embed on %s:%d\n" % (args.host, args.port))
    srv.serve_forever()


if __name__ == "__main__":
    main()
